export default {n:20,lang:"nl",srcLang:"en",track:"v2",title:"B1 Klaar!",sub:"Diminutives, Register & Consolidation",icon:"🏆",level:"B1.2",color:"#7B5EE8",lessons:[
  {id:"v2u20l1",title:"Verkleinwoorden",icon:"🔤",xp:20,board:true,steps:[
        {type:"intro",title:"Verkleinwoorden",desc:"Diminutives are EVERYWHERE in Dutch. 'Een kopje koffie', 'een broodje', 'een biertje'  -  even 'eventjes' (just a moment). The suffix changes based on the word's ending, and ALL diminutives become het-words. Let's master the full system.",goals:["Five diminutive suffix rules","All diminutives = het-words","Emotional/social uses of diminutives","Practice with common examples"]},
        {type:"tip",title:"🔤 The Five Diminutive Suffixes",text:"The basic suffix is -je. But it changes depending\non the last sound of the word:\n\n1. -JE (standard  -  after most consonants):\nhuis → huisje (little house)\nboek → boekje (little book)\nding → dingetje... wait, that's -etje! See rule 3.\n\n2. -TJE (after long vowel/diphthong/r/l/n):\nbloem → bloempje... wait, that's -pje! \nLet me be more precise:\n-tje after words ending in: -r, -l, -n, long vowel\nauto → autootje\ncafé → cafeetje\n\n3. -ETJE (after -l, -m, -n, -ng, -r + short vowel):\nding → dingetje\nbal → balletje\nman → mannetje\nring → ringetje\n\n4. -PJE (after -m with long vowel):\nbloem → bloempje (little flower)\nboom → boompje (little tree)\nraam → raampje (little window)\n\n5. -KJE (after -ng):\nkoning → koninkje (little king)\nring → ringetje... \n\nThe rules overlap and have exceptions!\nDon't memorize rules  -  learn by example.\nThe more Dutch you hear, the more natural it becomes."},
        {type:"teach",trg:"het kopje",src:"the little cup",pos:"noun",gender:"n",phonetic:"hut KOP-yuh",note:"kop → kopje. Standard -je suffix.\n'Een kopje koffie' is THE Dutch phrase.\nNote: ALL diminutives are HET-words!\n'De kop' → 'het kopje'.",example:"A: Wil je een kopje koffie?\nB: Mmm, dat klinkt lekker!\nA: Inderdaad.",exampleSrc:"A: Would you like a cup of coffee?\nB: Mmm, that sounds delicious!\nA: Indeed.",funFact:"Little cup. Het-word; ALL diminutives (-je) are het-words. This is a rule: adding -je turns any noun into a het-word, regardless of original gender."},
        {type:"teach",trg:"het broodje",src:"the bread roll / sandwich",pos:"noun",gender:"n",phonetic:"hut BROHT-yuh",note:"brood → broodje. -je suffix.\n'Een broodje' = a bread roll or filled roll.\nIn the Netherlands, THE lunch item.\nNotice: de brood → het broodje.",example:"A: Een broodje kaas, alstublieft.\nB: Mmm, dat klinkt lekker!\nA: Ja, precies!",exampleSrc:"A: A cheese sandwich, please.\nB: Mmm, that sounds delicious!\nA: Yes, exactly!",funFact:"Bread roll (u20 context). Het-word because diminutive. Diminutives always take het."},
        {type:"teach",trg:"het biertje",src:"a (little) beer",pos:"noun",gender:"n",phonetic:"hut BEER-tyuh",note:"bier → biertje. -tje suffix (after -r).\n'Een biertje doen' = to have a beer.\nDiminutive makes it sound casual and friendly.",example:"A: Zullen we een biertje drinken?\nB: Wil je er nog iets bij?\nA: Ja, precies!",exampleSrc:"A: Shall we have a beer?\nB: Would you like anything else with that?\nA: Yes, exactly!",funFact:"Little beer (u20 context). Diminutive. Same rule: -je → het."},
        {type:"teach",trg:"het bloempje",src:"a little flower",pos:"noun",gender:"n",phonetic:"hut BLOOM-pyuh",note:"bloem → bloempje. -pje suffix (after -m).\n'De bloem' → 'het bloempje'.\nThe -m + pje combination is very distinctive.",example:"A: Wat een leuk bloempje!\nB: Ik zal het voor je uitzoeken.\nA: Ja, precies!",exampleSrc:"A: What a cute little flower!\nB: I'll find out for you.\nA: Yes, exactly!",funFact:"Little flower. Diminutive of bloem. Shows the double-p before -je."},
        {type:"teach",trg:"het ringetje",src:"a little ring",pos:"noun",gender:"n",phonetic:"hut RING-uh-tyuh",note:"ring → ringetje. -etje suffix (after -ng).\nThe 'g' in -ng triggers -etje.\n'De ring' → 'het ringetje'.",example:"A: Een ringetje voor je vinger.\nB: Ik begrijp het.\nA: Mooi zo!",exampleSrc:"A: A little ring for your finger.\nB: I understand.\nA: Good!",funFact:"Little ring. Diminutive of ring. -etje after consonant cluster."},
        {type:"teach",trg:"het raampje",src:"a little window",pos:"noun",gender:"n",phonetic:"hut RAHM-pyuh",note:"raam → raampje. -pje suffix (after -m).\nUsed on planes, in cars, etc.\n'De raam' → 'het raampje'.",example:"A: Mag het raampje open?\nB: Wat een mooi huis!\nA: Inderdaad.",exampleSrc:"A: May the window be opened?\nB: What a nice house!\nA: Indeed.",funFact:"Little window. Diminutive of raam."},
        {type:"tip",title:"💡 Why Diminutives Matter",text:"Dutch uses diminutives A LOT more than English.\nThey don't always mean 'small':\n\n'Een kopje koffie' = a cup of coffee (normal size!)\n'Een biertje' = a beer (not small!)\n'Eventjes' = just a moment (not tiny!)\n'Een uurtje' = about an hour (not short!)\n\nDiminutives add:\n- Friendliness: 'een biertje' (casual beer)\n- Softening: 'een momentje' (just a moment, please)\n- Affection: 'mijn schatje' (my darling)\n- Minimizing: 'een probleempje' (a little problem)\n\nDutch without diminutives sounds cold and formal.\nThey're the sugar in the language."},
        {type:"mc",q:"ALL diminutives in Dutch are:",opts:["Het-words","De-words","Sometimes de, sometimes het","No article needed"],ans:"Het-words",hint:"What is the diminutive of 'kop'? Always neuter!"},
        {type:"fb",opts:["kopje","koppes","kopke","koppen"],hint:"What is the diminutive of 'kop'?",s:"Wil je een ___ koffie?",a:"kopje"},
        {type:"match",pairs:[{trg:"kopje",src:"-je (standard)"},{trg:"biertje",src:"-tje (after -r)"},{trg:"bloempje",src:"-pje (after -m)"},{trg:"ringetje",src:"-etje (after -ng)"}]},
        {type:"mc",q:"'Een biertje' doesn't actually mean a SMALL beer. It means:",opts:["A big beer","A friendly/casual beer","A warm beer","A fancy beer"],ans:"A friendly/casual beer",hint:"Diminutives add friendliness, not always smallness"},
        {type:"fb",opts:["pje","tje","je","etje"],hint:"After words ending in -m, which diminutive suffix?",s:"bloem → bloem___",a:"pje"},
        {type:"drag_fill",hint:"A cheese sandwich. Shall we have a beer?",s:"Een {1} kaas. Zullen we een {2} drinken?",blanks:{"1":"broodje","2":"biertje"},pool:["broodje","biertje","kopje","bloempje"]},
        {type:"mc",q:"What is the diminutive of 'boom' (tree)?",opts:["boomje","boometje","boompje","boomtje"],ans:"boompje",hint:"After -m with a long vowel: which diminutive suffix?"},
        {type:"fb",opts:["raampje","raamtje","raamje","raametje"],hint:"raam + diminutive suffix (think about what follows -m)",s:"Mag het ___ open? (little window)",a:"raampje"},
        {type:"drag_fill",hint:"A cup of coffee. A (casual) beer.",s:"Wil je een {1} koffie? Zullen we een {2} drinken?",blanks:{"1":"kopje","2":"biertje"},pool:["kopje","biertje","bloempje","ringetje"]},
        {type:"match",pairs:[{trg:"-je",src:"standard (kopje)"},{trg:"-tje",src:"after -r (biertje)"},{trg:"-pje",src:"after -m (bloempje)"},{trg:"-etje",src:"after -ng (ringetje)"}]},
        {type:"tr",mk:"v2u20_little_cup",dir:"produce"}
  ]},
  {id:"v2u20l2",title:"Formeel & Informeel",icon:"👔",xp:15,board:true,steps:[
        {type:"intro",title:"Formeel & Informeel",desc:"Register switching  -  the ability to move between formal and informal Dutch. From 'Zou u zo vriendelijk willen zijn om...' to 'Kun je even...?' This skill marks a true B1 speaker.",goals:["Formal phrases: Zou u zo vriendelijk willen zijn...","Informal equivalents: Kun je even...?","U vs jij in depth","Business Dutch essentials"]},
        {type:"tip",title:"👔 Register Spectrum",text:"VERY FORMAL (government/legal):\n'Hierbij verzoek ik u om...' = I hereby request you to...\n'Gelieve het formulier in te vullen.' = Please fill in the form.\n\nFORMAL (business):\n'Zou u zo vriendelijk willen zijn om mij te helpen?'\n= Would you be so kind as to help me?\n\nPOLITE:\n'Kunt u mij helpen?' = Can you help me?\n\nNEUTRAL:\n'Kun je me helpen?' = Can you help me?\n\nINFORMAL:\n'Help je me even?' = Will you help me?\n\nVERY INFORMAL:\n'Help even!' = Help out!\n\nThe Dutch default is NEUTRAL.\nFormal is for business, government, strangers.\nInformal is for friends, family, colleagues."},
        {type:"teach",trg:"Zou u zo vriendelijk willen zijn om...",src:"Would you be so kind as to...",pos:"intj",gender:null,phonetic:"zow uu zo VREEN-duh-luk VIL-un zayn om",note:"The MOST formal request structure.\nZou + u + zo vriendelijk + willen zijn + om te...\nUsed in formal letters, government, customer service.",example:"A: Zou u zo vriendelijk willen zijn om het raam te sluiten?\nB: Wat een mooi huis!\nA: Ja, precies!",exampleSrc:"A: Would you be so kind as to close the window?\nB: What a nice house!\nA: Yes, exactly!",funFact:"'Would you be so kind as to...' Ultra-formal request. Triple conditional: 'zou' + 'willen' + 'zijn' + 'om.' Business formality."},
        {type:"teach",trg:"hierbij",src:"hereby / with this",pos:"noun",gender:null,phonetic:"heer-BAY",note:"Very formal. 'Hierbij' = with this/hereby.\nOnly in formal letters and emails.\n'Hierbij bevestig ik dat...' = I hereby confirm that...",example:"A: Hierbij stuur ik u het rapport.\nB: O, is het al zo laat?\nA: Ja, precies!",exampleSrc:"A: Hereby I send you the report.\nB: Oh, is it that late already?\nA: Yes, exactly!",funFact:"Hereby / with this. Compound: 'hier' (here) + 'bij' (with/at). Formal written register. 'Hierbij verklaar ik' (hereby I declare)."},
        {type:"teach",trg:"gelieve",src:"please (very formal)",pos:"intj",gender:null,phonetic:"guh-LEE-vuh",note:"VERY formal 'please'. Government/legal language.\nNormal 'please' = 'alstublieft' (formal) / 'alsjeblieft' (informal).\n'Gelieve' is a step above even 'alstublieft'.",example:"A: Gelieve het formulier in te vullen.\nB: O, interessant!\nA: Ja, vind je niet?",exampleSrc:"A: Please fill in the form.\nB: Oh, interesting!\nA: Yes, don't you think?",funFact:"Please (very formal). Imperative: 'please be pleased to.' Ancient politeness. 'Gelieve te betalen' (please pay)."},
        {type:"mc",q:"The Dutch default register is:",opts:["Neutral","Formal","Very formal","Very informal"],ans:"Neutral",hint:"Not too formal, not too informal"},
        {type:"fb",opts:["Hierbij","Hier","Nu","Graag"],hint:"Hereby I send you the report",s:"___ stuur ik u het rapport.",a:"Hierbij"},
        {type:"match",pairs:[
          {trg:"Zou u zo vriendelijk willen zijn...",src:"Would you be so kind..."},
          {trg:"Kunt u mij helpen?",src:"Can you help me? (formal)"},
          {trg:"Kun je me even helpen?",src:"Can you help me? (informal)"},
          {trg:"Gelieve",src:"Please (very formal)"}
        ]},
        {type:"mc",q:"'Gelieve het formulier in te vullen' is:",opts:["Very informal","Very formal  -  government/legal","Formal","Neutral"],ans:"Very formal  -  government/legal",hint:"A very polite request form, even above 'alstublieft'"},
        {type:"fb",opts:["willen","kunnen","moeten","zullen"],hint:"Zou u zo vriendelijk _____ zijn om...",s:"Zou u zo vriendelijk ___ zijn om het raam te sluiten?",a:"willen"},
        {type:"mc",q:"Which phrase means 'I hereby confirm'?",opts:["Ik vind het","Ik zeg het","Ik bevestig hierbij","Ik denk dat"],ans:"Ik bevestig hierbij",hint:"A very formal word meaning 'hereby' in official letters"},
        {type:"fb",opts:["Gelieve","Graag","Wil","Probeer"],hint:"Very formal 'please' (government/legal)",s:"___ het formulier in te vullen.",a:"Gelieve"},
        {type:"drag_fill",hint:"Hereby I send. Please (very formal) fill in.",s:"{1} stuur ik u het rapport. {2} het formulier in te vullen.",blanks:{"1":"Hierbij","2":"Gelieve"},pool:["Hierbij","Gelieve","Graag","Alstublieft"]},
        {type:"match",pairs:[
          {trg:"Zou u zo vriendelijk willen zijn",src:"Very formal request"},
          {trg:"Kunt u mij helpen?",src:"Polite/formal"},
          {trg:"Kun je me even helpen?",src:"Neutral/informal"},
          {trg:"Help even!",src:"Very informal"}
        ]},
        {type:"mc",q:"Which second-person pronoun is correct in formal Dutch writing?",opts:["Jij/je (informal)","Men (impersonal)","Jullie (plural)","U (formal)"],ans:"U (formal)",hint:"This polite pronoun is always used in professional correspondence and with strangers"},
        {type:"fb",opts:["u","je","jij","jullie"],hint:"Formal you in a polite request",s:"Zou ___ zo vriendelijk willen zijn om mij te helpen?",a:"u"},
        {type:"mc",q:"'Kunt u mij helpen?' is which register?",opts:["Polite/formal","Neutral","Very informal","Very formal (government)"],ans:"Polite/formal",hint:"Kunt + u = ___ but not extremely ___"},
        {type:"drag_fill",hint:"Would YOU (formal) be so kind as to CLOSE the window?",s:"Zou {1} zo vriendelijk willen zijn om het raam te {2}?",blanks:{"1":"u","2":"sluiten"},pool:["u","sluiten","je","openen"]},
        {type:"tr",mk:"v2u20_formal_request",dir:"produce"}
  ]},
  {id:"v2u20l3",title:"Een Artikel Lezen",icon:"📰",xp:15,board:true,steps:[
        {type:"intro",title:"Een Artikel Lezen",desc:"Full reading comprehension at B1. A simplified newspaper article using ALL the grammar you've learned: passive voice, relative clauses, indirect speech, connectors, and more. Time to prove you can read real Dutch.",goals:["Read a ~150-word Dutch article","All B1 grammar in context","Answer comprehension questions","Identify grammar patterns in text"]},
        {type:"tip",title:"📰 Lees: Steeds Meer Nederlanders Werken Thuis",deepDive:{
          title:"Vertaling",
          text:"MORE AND MORE DUTCH PEOPLE WORK FROM HOME\n\nResearch has shown that more and more\nDutch people work from home. According to the\nCentral Bureau of Statistics (CBS), more than\nhalf of the working population now works at least\none day per week from home.\n\nThe Minister of Social Affairs declared that\nworking from home is being encouraged by the government.\n'It is good for the environment and for the\nwork-life balance,' said the minister.\n\nAlthough many employees are satisfied with\nworking from home, an expert warned that there\nare also disadvantages. 'Some people feel lonely,'\nshe told. 'You can't replace the work atmosphere\nat the office with a screen.'\n\nIn the coming years, new measures are expected\nto better regulate working from home."
        },text:"STEEDS MEER NEDERLANDERS WERKEN THUIS\n\nUit onderzoek is gebleken dat steeds meer\nNederlanders vanuit huis werken. Volgens het\nCentraal Bureau voor de Statistiek (CBS) werkt\ninmiddels meer dan de helft van de werkende\nbevolking minstens één dag per week thuis.\n\nDe minister van Sociale Zaken verklaarde dat\nhet thuiswerken wordt gestimuleerd door de overheid.\n'Het is goed voor het milieu en voor de\nwerk-privébalans,' zei de minister.\n\nHoewel veel werknemers tevreden zijn over het\nthuiswerken, waarschuwde een expert dat er ook\nnadelen zijn. 'Sommige mensen voelen zich eenzaam,'\nvertelde zij. 'De werksfeer op kantoor kun je niet\nvervangen door een beeldscherm.'\n\nDe komende jaren worden er nieuwe maatregelen\nverwacht om thuiswerken beter te regelen."},
        {type:"mc",q:"According to the article, how many people work from home?",opts:["More than half","About a third","Less than a quarter","Everyone"],ans:"More than half",hint:"The text mentions de helft. What quantity?"},
        {type:"fb",opts:["gebleken","gezegd","gevraagd","geschreven"],hint:"Past participle of 'blijken' (to appear/turn out)",s:"Uit onderzoek is ___ dat steeds meer mensen thuiswerken.",a:"gebleken"},
        {type:"mc",q:"'De werkende bevolking' uses a:",opts:["Past participle form","Present participle as adjective","Regular adjective only","Verb form conjugated"],ans:"Present participle as adjective",hint:"werkend + e = werkende (working, ongoing)"},
        {type:"mc",q:"'Het thuiswerken wordt gestimuleerd' is:",opts:["Active voice regular","State passive (zijn)","Passive voice (worden)","Impersonal passive form"],ans:"Passive voice (worden)",hint:"wordt + PP = process ___"},
        {type:"fb",opts:["Hoewel","Omdat","Doordat","Nadat"],hint:"ALTHOUGH many employees are satisfied...",s:"___ veel werknemers tevreden zijn, zijn er ook nadelen.",a:"Hoewel"},
        {type:"fb",opts:["gebleken","gezegd","gevraagd","gelezen"],hint:"Strong verb from blijken: ge- + vowel change",s:"Uit onderzoek is ___ dat thuiswerken populair is.",a:"gebleken"},
        {type:"mc",q:"'Het thuiswerken wordt gestimuleerd door de overheid.' Who does the stimulating?",opts:["The employees collectively","The experts in the field","The minister personally","The government (overheid)"],ans:"The government (overheid)",hint:"door de ___ = by the ___"},
        {type:"drag_fill",hint:"The minister declared. An expert warned.",s:"De minister {1} dat thuiswerken goed is. Een expert {2} dat er ook nadelen zijn.",blanks:{"1":"verklaarde","2":"waarschuwde"},pool:["verklaarde","waarschuwde","vertelde","vroeg"]},
        {type:"match",pairs:[{trg:"steeds meer",src:"more and more"},{trg:"de werkende bevolking",src:"the working population"},{trg:"het milieu",src:"the environment"},{trg:"de nadelen",src:"the disadvantages"}]},
        {type:"fb",opts:["Hoewel","Omdat","Doordat","Zodra"],hint:"ALTHOUGH many employees are satisfied",s:"___ veel werknemers tevreden zijn, zijn er ook nadelen.",a:"Hoewel"},
        {type:"mc",q:"'Sommige mensen voelen zich eenzaam.' What does 'eenzaam' mean?",opts:["Lonely","Busy","Happy","Tired"],ans:"Lonely",hint:"A feeling of isolation when working from home"},
        {type:"fb",opts:["werkt","werken","werkend","gewerkt"],hint:"meer dan de helft = singular subject",s:"Volgens het CBS ___ meer dan de helft thuis.",a:"werkt"},
        {type:"mc",q:"The article uses indirect speech: 'De minister verklaarde dat...' This is:",opts:["A direct spoken quote","Reported speech with 'dat'","A yes/no question","A direct command"],ans:"Reported speech with 'dat'",hint:"This conjunction introduces what was said without direct quotation marks"},
        {type:"drag_fill",hint:"Although... there are also disadvantages.",s:"{1} veel werknemers tevreden zijn, zijn er ook {2}.",blanks:{"1":"Hoewel","2":"nadelen"},pool:["Hoewel","nadelen","Omdat","voordelen"]},
        {type:"fb",opts:["werkende","gewerkte","werkend","werkde"],hint:"A verb form ending in -d(e) used as an adjective before a noun",s:"De ___ bevolking werkt minstens een dag thuis.",a:"werkende"},
        {type:"match",pairs:[{trg:"het thuiswerken",src:"working from home"},{trg:"de werk-privebalans",src:"work-life balance"},{trg:"de werksfeer",src:"work atmosphere"},{trg:"de maatregelen",src:"the measures"}]},
        {type:"mc",q:"'De komende jaren worden er nieuwe maatregelen verwacht'  -  'komende' means:",opts:["Past event","Going away","Coming/upcoming","Leaving soon"],ans:"Coming/upcoming",hint:"Present participle: komend = c..."}
  ]},
  {id:"v2u20l4",title:"Een E-mail Schrijven",icon:"✉️",xp:15,board:true,steps:[
        {type:"intro",title:"Een E-mail Schrijven",desc:"Structured writing practice. You'll work through a formal complaint email step by step, using the register and vocabulary you've learned. Opening, problem description, request, closing.",goals:["Write a formal complaint email","Structure: opening → problem → request → closing","Use formal register: Geachte, Zou u, Met vriendelijke groet","Translation exercises for email phrases"]},
        {type:"tip",title:"✉️ De Klachtenbrief (Complaint Email)",text:"STRUCTURE:\n\n1. OPENING:\nGeachte heer/mevrouw,\n\n2. REFERENCE:\nNaar aanleiding van [situation], schrijf ik u...\n= With regard to [situation], I am writing to you...\n\n3. PROBLEM:\nIk wil u informeren dat...\nHet probleem is dat...\nDit is niet wat ik had verwacht.\n\n4. REQUEST:\nZou u zo vriendelijk willen zijn om...\nIk zou het op prijs stellen als...\n= I would appreciate it if...\nKunt u mij laten weten wanneer dit wordt opgelost?\n\n5. CLOSING:\nIk hoor graag van u.\n= I look forward to hearing from you.\nMet vriendelijke groet,\n[naam]\n\nEXAMPLE:\nGeachte heer/mevrouw,\n\nNaar aanleiding van mijn bestelling van 15 februari\nwil ik u melden dat het product beschadigd is\naangekomen. Dit is niet wat ik had verwacht.\n\nZou u zo vriendelijk willen zijn om een vervangend\nproduct te sturen? Ik hoor graag van u.\n\nMet vriendelijke groet,\nAnna Bakker"},
        {type:"mc",q:"'Ik zou het op prijs stellen als...' means:",opts:["I would appreciate it if...","I would complain if...","I would be angry if...","I would understand if..."],ans:"I would appreciate it if...",hint:"Op prijs ___: a formal way to say 'to a...'"},
        {type:"fb",opts:["van","over","aan","met"],hint:"I look forward to hearing FROM you",s:"Ik hoor graag ___ u.",a:"van"},
        {type:"match",pairs:[
          {trg:"Geachte heer/mevrouw",src:"Dear Sir/Madam"},
          {trg:"Naar aanleiding van",src:"With regard to"},
          {trg:"Ik hoor graag van u",src:"I look forward to hearing from you"},
          {trg:"Met vriendelijke groet",src:"Kind regards"}
        ]},
        {type:"mc",q:"'Dit is niet wat ik had verwacht' uses:",opts:["Present tense","Past perfect","Simple past","Future"],ans:"Past perfect",hint:"had verwacht = had expected"},
        {type:"fb",opts:["aanleiding","reden","oorzaak","gevolg"],hint:"'Naar ___ van' = with regard to (formal phrase)",s:"Naar ___ van mijn bestelling, schrijf ik u.",a:"aanleiding"},
        {type:"mc",q:"'Dit is niet wat ik had verwacht.' Which tense is 'had verwacht'?",opts:["Present perfect","Simple past","Past perfect","Future"],ans:"Past perfect",hint:"had + PP: which compound tense for earlier-than-___ events?"},
        {type:"match",pairs:[
          {trg:"Geachte heer/mevrouw",src:"Dear Sir/Madam"},
          {trg:"Naar aanleiding van",src:"With regard to"},
          {trg:"Met vriendelijke groet",src:"Kind regards"},
          {trg:"Ik hoor graag van u",src:"I look forward to hearing from you"}
        ]},
        {type:"drag_fill",hint:"Dear Sir/Madam. Kind regards.",s:"{1} heer/mevrouw, ik wil u melden dat het product beschadigd is. {2} vriendelijke groet, Anna.",blanks:{"1":"Geachte","2":"Met"},pool:["Geachte","Met","Beste","Van"]},
        {type:"fb",opts:["stellen","vinden","hebben","nemen"],hint:"Op prijs ___: a formal way to say 'to appreciate'",s:"Ik zou het op prijs ___ als u het product vervangt.",a:"stellen"},
        {type:"mc",q:"The correct order for a complaint email is:",opts:["Closing, problem, opening, request","Problem, request, opening, closing","Request, opening, problem, closing","Opening, reference, problem, request, closing"],ans:"Opening, reference, problem, request, closing",hint:"Geachte first, Met vriendelijke groet last"},
        {type:"fb",opts:["weten","zien","horen","doen"],hint:"Can you let me KNOW when this will be resolved?",s:"Kunt u mij laten ___ wanneer dit wordt opgelost?",a:"weten"},
        {type:"mc",q:"'Het product is beschadigd aangekomen.' What does 'beschadigd' mean?",opts:["Damaged","Lost","Late","Returned"],ans:"Damaged",hint:"be- + schade + -d: what does this adjective mean?"},
        {type:"drag_fill",hint:"I look forward to hearing. Would you be so kind?",s:"Ik {1} graag van u. {2} u zo vriendelijk willen zijn om te antwoorden?",blanks:{"1":"hoor","2":"Zou"},pool:["hoor","Zou","schrijf","Kunt"]},
        {type:"match",pairs:[{trg:"beschadigd",src:"damaged"},{trg:"vervangend product",src:"replacement product"},{trg:"mijn bestelling",src:"my order"},{trg:"op prijs stellen",src:"to appreciate"}]},
        {type:"fb",opts:["Met","Van","Uit","Bij"],hint:"Dutch formal email closing: ___ vriendelijke groet (the opening word of 'Kind regards')",s:"___ vriendelijke groet, Jan de Vries.",a:"Met"},
        {type:"mc",q:"You use 'u' instead of 'jij' in a complaint email because:",opts:["The person is older","It is formal business writing","You are angry","The email is long"],ans:"It is formal business writing",hint:"___ register requires 'u'"},
        {type:"fb",opts:["Zou","Kunt","Wilt","Moet"],hint:"Would you be so kind as to...",s:"___ u zo vriendelijk willen zijn om een nieuw product te sturen?",a:"Zou"}
  ]},
  {id:"v2u20l5",title:"Mijn Verhaal Vertellen",icon:"📖",xp:15,board:true,steps:[
        {type:"intro",title:"Mijn Verhaal Vertellen",desc:"Connected speech at B1. Tell the story of your week, your move to the Netherlands, or your career change. Use all tenses, connectors, and opinions. This is what B1 is about: producing connected text on familiar topics.",goals:["Use all tenses in connected speech","Time markers: eerst, toen, daarna, uiteindelijk","Give reasons and opinions","Produce connected text"]},
        {type:"tip",title:"📖 Time Markers for Stories",text:"To tell a connected story, use TIME MARKERS:\n\nEerst... = First...\nToen... = Then... (past)\nDaarna... = After that...\nVervolgens... = Subsequently...\nIntussen... = Meanwhile...\nUiteindelijk... = Eventually...\nTen slotte... = Finally...\n\nExample story:\nEerst woonde ik in België.\nToen kreeg ik een baan in Amsterdam.\nDaarna ben ik verhuisd.\nIntussen had ik al een huis gevonden.\nUiteindelijk begon ik met mijn nieuwe werk.\nTen slotte voelde ik me thuis in Nederland."},
        {type:"teach",trg:"uiteindelijk",src:"eventually / in the end",pos:"noun",gender:null,phonetic:"OW-tun-duh-luk",note:"'Uiteindelijk' = in the end, eventually.\nVery useful for concluding a story.\n'Uiteindelijk is alles goed gekomen.'\n= In the end everything turned out well.",example:"A: Uiteindelijk vond ik een baan.\nB: Dat klinkt als een goede baan.\nA: Inderdaad.",exampleSrc:"A: Eventually I found a job.\nB: That sounds like a good job.\nA: Indeed.",funFact:"Finally / in the end. Compound: 'uit' (out) + 'ein' (end) + 'delijk' (-ly). Literally 'out-end-ly.' Narrative resolution marker."},
        {type:"teach",trg:"vervolgens",src:"subsequently / then",pos:"noun",gender:null,phonetic:"fur-VOL-guns",note:"'Vervolgens' = next/then (more formal than 'daarna').\nGood for structured storytelling.\n'Daarna' (after that) = more casual version.",example:"A: Vervolgens ging ik naar de gemeente.\nB: Interessant punt!\nA: Klopt!",exampleSrc:"A: Subsequently I went to the municipality.\nB: Interesting point!\nA: Right!",funFact:"Subsequently / then. From 'vervolgen' (to continue). Connective for sequence in formal writing."},
        {type:"teach",trg:"ten slotte",src:"finally / lastly",pos:"intj",gender:null,phonetic:"ten SLOT-tuh",note:"'Ten slotte' = lastly/in conclusion.\nUsed for the LAST point in a series.\n'Tot slot' = same meaning, slightly less formal.",example:"A: Ten slotte wil ik iedereen bedanken.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: Finally, I want to thank everyone.\nB: That's good to know.\nA: Yes, for sure!",funFact:"Finally / lastly. Archaic genitive: 'ten' (to the) + 'slotte' (end). Essay-ending connector. Pair with 'ten eerste' (firstly)."},
        {type:"mc",q:"Order these: eerst, uiteindelijk, daarna, ten slotte",opts:["eerst → daarna → uiteindelijk → ten slotte","uiteindelijk → eerst → ten slotte → daarna","ten slotte → daarna → eerst → uiteindelijk","daarna → eerst → ten slotte → uiteindelijk"],ans:"eerst → daarna → uiteindelijk → ten slotte",hint:"First → after that → eventually → finally"},
        {type:"fb",opts:["Uiteindelijk","Eerst","Daarna","Vervolgens"],hint:"In the end, eventually",s:"___ vond ik een baan. (eventually)",a:"Uiteindelijk"},
        {type:"match",pairs:[{trg:"eerst",src:"first"},{trg:"daarna",src:"after that"},{trg:"vervolgens",src:"subsequently"},{trg:"ten slotte",src:"finally"}]},
        {type:"drag_fill",hint:"First I lived in Belgium. Then I got a job.",s:"{1} woonde ik in België. {2} kreeg ik een baan in Amsterdam.",blanks:{"1":"Eerst","2":"Toen"},pool:["Eerst","Toen","Daarna","Uiteindelijk"]},
        {type:"mc",q:"'Intussen had ik al een huis gevonden.' What does 'intussen' mean?",opts:["First","Meanwhile","Finally","After that"],ans:"Meanwhile",hint:"In between / at the same time"},
        {type:"fb",opts:["Vervolgens","Intussen","Uiteindelijk","Eerst"],hint:"Subsequently / then (more formal than 'then')",s:"___ ging ik naar de gemeente.",a:"Vervolgens"},
        {type:"drag_fill",hint:"First I lived in Belgium. In the end everything turned out well.",s:"{1} woonde ik in België. {2} is alles goed gekomen.",blanks:{"1":"Eerst","2":"Uiteindelijk"},pool:["Eerst","Uiteindelijk","Intussen","Vervolgens"]},
        {type:"match",pairs:[{trg:"eerst",src:"first"},{trg:"intussen",src:"meanwhile"},{trg:"uiteindelijk",src:"eventually"},{trg:"ten slotte",src:"finally/lastly"}]},
        {type:"mc",q:"'Vervolgens' is a more formal version of:",opts:["Eerst","Ten slotte","Daarna","Intussen"],ans:"Daarna",hint:"Both mean 'then/after that'"},
        {type:"fb",opts:["Intussen","Eerst","Daarna","Ten slotte"],hint:"A Dutch word meaning 'in the meantime' or 'during that period'",s:"___ had ik al een huis gevonden.",a:"Intussen"},
        {type:"drag_fill",hint:"Then I got a job. Subsequently I went to the municipality. Eventually I felt at home.",s:"{1} kreeg ik een baan. {2} ging ik naar de gemeente. {3} voelde ik me thuis.",blanks:{"1":"Toen","2":"Vervolgens","3":"Uiteindelijk"},pool:["Toen","Vervolgens","Uiteindelijk","Eerst","Intussen"]},
        {type:"mc",q:"Which time marker would you use LAST in a story?",opts:["Eerst","Daarna","Vervolgens","Ten slotte"],ans:"Ten slotte",hint:"Finally / in conclusion = the last point"},
        {type:"fb",opts:["Daarna","Eerst","Ten slotte","Intussen"],hint:"After that I moved to Amsterdam",s:"___ ben ik verhuisd naar Amsterdam.",a:"Daarna"},
        {type:"fb",opts:["Ten slotte","Eerst","Daarna","Intussen"],hint:"Finally / lastly",s:"___ wil ik iedereen bedanken.",a:"Ten slotte"}
  ]},
  {id:"v2u20l6",title:"Nederland in Getallen",icon:"📊",xp:15,board:true,steps:[
        {type:"intro",title:"Nederland in Getallen",desc:"Statistics and data vocabulary. 'De helft van de bevolking fietst.' How to talk about percentages, averages, and proportions  -  essential for reading news and understanding reports.",goals:["Data vocabulary: percentage, gemiddeld, de helft","Proportion words: een derde, een kwart","Approximate quantities: ongeveer, meer dan","Read an infographic about the Netherlands"]},
        {type:"teach",trg:"het percentage",src:"the percentage",pos:"noun",gender:"n",phonetic:"hut per-sen-TAH-zhuh",note:"Het-word. 'Procent' = percent.\n'50 procent' = 50 percent.\n'Het percentage daalt/stijgt.' = The percentage drops/rises.",example:"A: Het percentage is gestegen.\nB: Wat leuk!\nA: Ja, inderdaad!",exampleSrc:"A: The percentage has risen.\nB: How nice!\nA: Yes, indeed!",funFact:"latin cousin of English 'percentage', French 'pourcentage'."},
        {type:"teach",trg:"gemiddeld",src:"on average / average",pos:"verb",gender:null,phonetic:"guh-MI-dult",note:"'Gemiddeld' = on average (adverb) / average (adjective).\n'Het gemiddelde' = the average (noun).\n'Boven/onder het gemiddelde' = above/below average.",example:"A: Gemiddeld werken Nederlanders 32 uur per week.\nB: Dat klinkt als een goede baan.\nA: Goed punt.",exampleSrc:"A: On average, Dutch people work 32 hours per week.\nB: That sounds like a good job.\nA: Good point.",funFact:"On average / average. From 'middelen' (to average) + ge- + -d. Statistical vocabulary."},
        {type:"teach",trg:"de helft",src:"the half / half",pos:"noun",gender:"c",phonetic:"duh helft",note:"De-word. 'De helft van...' = half of...\n'De bevolking' = the population.\n'Meer dan de helft' = more than half.",example:"A: De helft van de bevolking fietst.\nB: Dat is niet ver hiervandaan.\nA: Klopt!",exampleSrc:"A: Half of the population cycles.\nB: That's not far from here.\nA: Right!",funFact:"Half. From Germanic 'halba.' Cognate with English 'half.' Feminine despite Germanic neuter origins."},
        {type:"teach",trg:"een derde",src:"a third",pos:"noun",gender:null,phonetic:"un DER-duh",note:"'Een derde' = a third (1/3).\n'Een kwart' = a quarter (1/4).\n'Twee derde' = two thirds (2/3).",example:"A: Een derde van de studenten werkt parttime.\nB: Hoe bevalt het werk?\nA: Klopt!",exampleSrc:"A: A third of the students works part-time.\nB: How do you like the work?\nA: Right!",funFact:"A third. Fraction. 'Een' (a/one) + 'derde' (third). Regular ordinal + 'e' = fractional noun."},
        {type:"teach",trg:"ongeveer",src:"approximately / about",pos:"adv",gender:null,phonetic:"on-guh-VAYR",note:"'Ongeveer' = approximately.\nAlso: 'circa' (more formal), 'zo'n' (informal).\n'Zo'n 17 miljoen' = about 17 million.",example:"A: Er wonen ongeveer 17 miljoen mensen in Nederland.\nB: Wat een mooi huis!\nA: Goed punt.",exampleSrc:"A: Approximately 17 million people live in the Netherlands.\nB: What a nice house!\nA: Good point.",funFact:"Common in everyday Dutch. Position in the sentence follows the V2 rule: verb stays second."},
        {type:"tip",title:"📊 Nederland in Getallen",text:"🚲 Meer fietsen dan mensen: ~23 miljoen fietsen\nvoor ~17,9 miljoen inwoners.\n\n🏠 Gemiddelde huurprijs: ~€1.100 per maand.\n\n☕ Koffie per persoon: ~150 liter per jaar.\nNederland = top 5 koffiedrinkers ter wereld.\n\n🌊 Onder zeeniveau: ~26% van Nederland ligt\nonder de zeespiegel.\n\n📚 Talen: Ongeveer 90% van de Nederlanders\nspreekt Engels. Meer dan de helft spreekt\nminstens 2 vreemde talen.\n\n💰 Parttime: Een derde van de banen is parttime.\nHoogste percentage in Europa."},
        {type:"mc",q:"'Gemiddeld' means:",opts:["On average","Minimum","Maximum","Exactly"],ans:"On average",hint:"Statistical middle value, not a precise number"},
        {type:"fb",opts:["helft","derde","kwart","percentage"],hint:"Half of the population",s:"De ___ van de bevolking fietst.",a:"helft"},
        {type:"match",pairs:[{trg:"de helft",src:"half"},{trg:"een derde",src:"a third"},{trg:"een kwart",src:"a quarter"},{trg:"ongeveer",src:"approximately"}]},
        {type:"fb",opts:["ongeveer","precies","altijd","gemiddeld"],hint:"Approximately 17 million",s:"Er wonen ___ 17 miljoen mensen in Nederland.",a:"ongeveer"},
        {type:"mc",q:"How many bicycles does the Netherlands have?",opts:["About 5 million","About 23 million","About 12 million","About 50 million"],ans:"About 23 million",hint:"More bikes than people!"},
        {type:"fb",opts:["derde","kwart","helft","percentage"],hint:"Een ___ = 1/3 (ordinal number as fraction)",s:"Een ___ van de studenten werkt parttime.",a:"derde"},
        {type:"mc",q:"'Boven het gemiddelde' means:",opts:["Below average","Exactly average","Above average","Far from average"],ans:"Above average",hint:"Boven = a..., het gemiddelde = the a..."},
        {type:"drag_fill",hint:"Half cycles. A third works part-time.",s:"De {1} van de bevolking fietst. Een {2} werkt parttime.",blanks:{"1":"helft","2":"derde"},pool:["helft","derde","kwart","percentage"]},
        {type:"match",pairs:[{trg:"het percentage",src:"the percentage"},{trg:"gemiddeld",src:"on average"},{trg:"een kwart",src:"a quarter"},{trg:"de helft",src:"the half"}]},
        {type:"fb",opts:["Ongeveer","Precies","Altijd","Helemaal"],hint:"Approximately 90 percent",s:"___ 90 procent van de Nederlanders spreekt Engels.",a:"Ongeveer"},
        {type:"mc",q:"'Gemiddeld werken Nederlanders 32 uur per week.' Is this:",opts:["An exact number for everyone","The legal minimum","The legal maximum","An average across the population"],ans:"An average across the population",hint:"Gemiddeld: a statistical term, not exact per person"},
        {type:"tr",mk:"v2u20_half_population",dir:"produce"}
  ]},
  {id:"v2u20l7",title:"Alles Samen",icon:"🧩",xp:20,board:true,steps:[
        {type:"intro",title:"Alles Samen",desc:"The comprehensive B1 grammar review. Past perfect, zou/zouden, passive voice, er (all 5 uses), indirect speech, participle adjectives, word formation  -  your complete B1 toolkit in one lesson.",goals:["Review ALL B1 grammar patterns","Past perfect, zou, passive, er, indirect speech","Participles, compounds, inseparable prefixes","One question per major grammar topic"]},
        {type:"mc",q:"Past perfect: 'Ik ___ al gegeten toen hij kwam.'",opts:["had","heb","ben","was"],ans:"had",hint:"Past perfect with hebben: ___ + PP"},
        {type:"fb",opts:["helpen","geholpen","hielp","helpt"],hint:"Zou + infinitive (conditional)",s:"Zou je mij kunnen ___? (help)",a:"helpen"},
        {type:"mc",q:"'De brief wordt geschreven' vs 'De brief is geschreven':",opts:["Same meaning","worden = process, zijn = result","worden = past, zijn = present","worden = formal, zijn = informal"],ans:"worden = process, zijn = result",hint:"___ = becoming, ___ = done"},
        {type:"fb",opts:["wordt","is","werd","zijn"],hint:"No smoking here (er + worden + PP)",s:"Er ___ hier niet gerookt. (impersonal passive)",a:"wordt"},
        {type:"mc",q:"'Heb je er drie?'  -  which er is this?",opts:["Existential er","Locative er","Partitive er","Prepositional er"],ans:"Partitive er",hint:"Er drie = three of them (quantity)"},
        {type:"fb",opts:["was","is","ben","wordt"],hint:"ben → was in indirect speech",s:"Hij zei dat hij moe ___. (tense backshift)",a:"was"},
        {type:"mc",q:"'De werkende bevolking' uses a:",opts:["Past participle","Noun","Regular verb","Present participle"],ans:"Present participle",hint:"werkend = working (ongoing, ___)"},
        {type:"fb",opts:["ontdekt","geontdekt","ontdekken","ontdekte"],hint:"No ge- with inseparable prefixes!",s:"PP of 'ontdekken' (inseparable prefix):",a:"ontdekt"},
        {type:"mc",q:"'Het huis waarin ik woon'  -  for people, this becomes:",opts:["preposition + wie","waar + preposition","die/dat","of"],ans:"preposition + wie",hint:"Things: waar+prep. People: prep+___."},
        {type:"fb",opts:["Voordat","Nadat","Zodra","Hoewel"],hint:"BEFORE the meeting started...",s:"___ de vergadering begon, had ik al koffie gedronken.",a:"Voordat"},
        {type:"fb",opts:["fiets","fietsen","fietst","gefietst"],hint:"Present tense ik-form: drop -en from the cycling verb",s:"Hoewel het regent, ___ ik toch. (cycle)",a:"fiets"},
        {type:"drag_fill",hint:"Past perfect: had + PP. Simple past: kwam.",s:"Ik {1} al gegeten toen hij {2}.",blanks:{"1":"had","2":"kwam"},pool:["had","kwam","heb","komt"]},
        {type:"match",pairs:[{trg:"past perfect",src:"had + past participle"},{trg:"passive (worden)",src:"wordt/werd + PP"},{trg:"conditional",src:"zou + infinitive"},{trg:"indirect speech",src:"dat + verb final"}]},
        {type:"mc",q:"'Het geschreven woord is krachtig.' Is 'geschreven' here:",opts:["A verb","A past participle used as adjective","A present participle","An adverb"],ans:"A past participle used as adjective",hint:"geschreven woord = the written word (completed action)"},
        {type:"fb",opts:["sustainable","expensive","dangerous","traditional"],hint:"Duurzaam means lasting/environmentally responsible",s:"'Duurzaam' means:",a:"sustainable"},
        {type:"drag_fill",hint:"Past passive (werd). Present impersonal passive (wordt).",s:"De wet {1} vorig jaar aangenomen. Er {2} hier niet gerookt.",blanks:{"1":"werd","2":"wordt"},pool:["werd","wordt","is","was"]},
        {type:"mc",q:"In 'de zonnebril', why is it a de-word?",opts:["Zon is a de-word","All compounds are de-words","Bril is a de-word (last word rule)","Sunglasses are always de"],ans:"Bril is a de-word (last word rule)",hint:"___ ___ determines: de ___ = de zonne___"},
        {type:"mc",q:"All diminutives in Dutch are:",opts:["De-words","No article","Both possible","Het-words"],ans:"Het-words",hint:"What is the diminutive of 'kop'? Always neuter!"}
  ]},
  {id:"v2u20l8",title:"🎉 B1 Klaar!",icon:"🏆",xp:25,board:true,steps:[
        {type:"intro",title:"🎉 B1 Klaar!",desc:"You made it. From 'Hallo' to passive voice, from counting to one to writing formal complaint emails, from 'Ik ben...' to 'Hij zei dat hij zou komen.' You are a B1 Dutch speaker. This is your celebration  -  and your final challenge.",goals:["Celebrate your B1 achievement","Your complete grammar toolkit","Comprehensive mixed review","What comes next: B2 preview"]},
        {type:"tip",title:"🏆 What You Can Do at B1",text:"✅ You can handle most situations in the Netherlands.\n✅ You can read simplified news articles.\n✅ You can write formal and informal emails.\n✅ You can tell stories about the past (3 past tenses!).\n✅ You can express and defend opinions.\n✅ You can describe conditions and hypotheticals (zou).\n✅ You can understand passive voice in news.\n✅ You can report what others said.\n✅ You can navigate Dutch bureaucracy.\n✅ You can understand Dutch culture and customs.\n\nYour grammar toolkit:\nA1: present tense, V2, zijn/hebben, de/het\nA1-A2: modals, perfect tense, 't kofschip\nA2: separable verbs, adjectives, simple past\nA2: relative clauses (die/dat), subordination\nB1: past perfect, zou, passive, er (5 types)\nB1: indirect speech, participles, compounds\nB1: infinitive constructions, verb clusters\n\nVocabulary: ~1,200 explicitly taught words.\nPlus hundreds more from context and exposure."},
        {type:"mc",q:"'Ik had al gegeten toen hij kwam'  -  which happened first?",opts:["Ik at","Hij kwam","Both at the same time","Neither"],ans:"Ik at",hint:"Past perfect = the EARLIER event"},
        {type:"fb",opts:["werd","wordt","is","was"],hint:"Past tense passive auxiliary for singular subjects",s:"De wet ___ vorig jaar aangenomen. (passive, past)",a:"werd"},
        {type:"mc",q:"'Er wordt hier gewerkt'  -  what type of passive?",opts:["Normal passive","Impersonal passive","State passive","Not passive"],ans:"Impersonal passive",hint:"No real subject  -  er fills the gap"},
        {type:"match",pairs:[{trg:"hoewel",src:"although"},{trg:"doordat",src:"because (external)"},{trg:"zodat",src:"so that"},{trg:"tenzij",src:"unless"},{trg:"het broodje",src:"the bread roll / sandwich"}]},
        {type:"fb",opts:["of","dat","wat","als"],hint:"Indirect yes/no question → of",s:"Ze vroeg ___ ik morgen kwam.",a:"of"},
        {type:"mc",q:"PP of 'verbeteren' (inseparable prefix):",opts:["verbetert","geverbeterd","verbeterd","gebeterd"],ans:"verbeterd",hint:"Inseparable prefix = no ge-!"},
        {type:"drag_fill",hint:"CLOSED door (past PP). GROWING problem (present PP).",s:"De {1} deur. Een {2} probleem.",blanks:{"1":"gesloten","2":"groeiend"},pool:["gesloten","groeiend","werkende","geschreven"]},
        {type:"fb",opts:["Zou","Kunt","Wilt","Bent"],hint:"Would you be so kind...",s:"___ u zo vriendelijk willen zijn om mij te helpen?",a:"Zou"},
        {type:"mc",q:"'Zou u zo vriendelijk willen zijn...' Which register is this?",opts:["Slang","Casual","Informal written","Very formal/polite"],ans:"Very formal/polite",hint:"Zou + u = the most ___ Dutch gets"},
        {type:"fb",opts:["milieu","weer","kantoor","verkeer"],hint:"The environment is important",s:"Het ___ is belangrijk voor iedereen.",a:"milieu"},
        {type:"mc",q:"'De komende week ga ik op vakantie.' What does 'komende' describe?",opts:["An ongoing/upcoming event","A past event","A completed action","A hypothetical"],ans:"An ongoing/upcoming event",hint:"Present participle: komend = coming/next"},
        {type:"drag_fill",hint:"First... After that...",s:"{1} woonde ik in België. {2} ben ik naar Nederland verhuisd.",blanks:{"1":"Eerst","2":"Daarna"},pool:["Eerst","Daarna","Uiteindelijk","Ten slotte"]},
        {type:"fb",opts:["kopje","tas","beker","glas"],hint:"The diminutive of kop",s:"Een ___ koffie, alstublieft.",a:"kopje"},
        {type:"match",pairs:[{trg:"het kopje",src:"little cup (het-word)"},{trg:"de vervuiling",src:"the pollution"},{trg:"gemiddeld",src:"on average"},{trg:"uiteindelijk",src:"eventually"}]},
        {type:"mc",q:"All Dutch diminutives become:",opts:["De-words","Het-words","Either de or het","No article needed"],ans:"Het-words",hint:"Diminutive of 'kop': always neuter article"},
        {type:"tip",title:"🔮 Wat Komt Er Hierna? (B2 Preview)",text:"At B2 you will learn:\n\n📖 Longer, more complex texts (newspaper editorials,\n   short stories, academic summaries)\n\n📐 More passive constructions (worden + past tenses)\n\n📐 Extended conditional (als...zou...hebben)\n\n📐 Subjunctive remnants (het zij zo, moge het lukken)\n\n📐 Academic register (wetenschappelijke teksten)\n\n📐 Idiomatic expressions (op de hoogte zijn,\n   aan de slag gaan, voor de hand liggen)\n\n📐 Nuanced opinion & argumentation\n\n📐 Literary Dutch (reading comprehension)\n\nBut that's for later.\nFor now: you are B1.\n\nJe hebt het gehaald. Gefeliciteerd! 🎉\n= You made it. Congratulations!\n\n🇳🇱 Tot ziens bij B2! 🇳🇱"}
  ]},
  {id:"nlv2_u20l_b1_abstract",title:"Abstracte Begrippen",icon:"💡",xp:20,board:true,steps:[
        {type:"intro",title:"Abstracte Begrippen",desc:"Abstract nouns and civic verbs are the vocabulary of adult conversation: goals, beliefs, consequences, areas of life. These words appear constantly in Dutch news, debate, and everyday discussion at B1 level.",goals:["Nine key B1 abstract and civic words","Articles: de versus het for abstract nouns","Three inseparable-prefix verbs","Production practice with fb and drag_fill"]},
        {type:"teach",trg:"de betekenis",src:"the meaning",pos:"noun",gender:"c",note:"De-word. Plural: betekenissen.\n'Wat is de betekenis van dit woord?' = What does this word mean?\n'Betekenis hebben' = to have significance.",example:"A: Wat is de betekenis van dit woord?\nB: Het betekent hetzelfde als 'doel'.\nA: Nu begrijp ik het.",exampleSrc:"A: What is the meaning of this word?\nB: It means the same as 'goal'.\nA: Now I understand it.",funFact:"From 'betekenen' (to mean/signify). The suffix -nis creates abstract nouns from verbs. Same pattern: begrijpen → begrijpenis, though 'betekenis' is far more common."},
        {type:"teach",trg:"het doel",src:"the goal / purpose",pos:"noun",gender:"n",note:"Het-word. Plural: doelen.\n'Het doel is...' = The goal is...\n'Een doel bereiken' = to reach a goal.\n'Doelgericht' = goal-oriented.",example:"A: Wat is het doel van dit project?\nB: Het doel is de economie te verbeteren.\nA: Dat is een goed doel.",exampleSrc:"A: What is the goal of this project?\nB: The goal is to improve the economy.\nA: That is a good goal.",funFact:"Cognate with German 'Ziel' (goal)? No, actually with English 'deal' via Proto-Germanic. Also used in sport: 'een doelpunt scoren' = to score a goal."},
        {type:"teach",trg:"de hoop",src:"the hope",pos:"noun",gender:"c",note:"De-word. 'Hopen' = to hope (verb).\n'Ik hoop dat...' = I hope that...\n'Er is hoop' = there is hope.\nNot to confuse with 'de hoop' = the heap/pile.",example:"A: Er is hoop dat de situatie verbetert.\nB: Ja, de politiek werkt aan oplossingen.\nA: Ik hoop het ook.",exampleSrc:"A: There is hope that the situation will improve.\nB: Yes, politics is working on solutions.\nA: I hope so too.",funFact:"Same word for 'hope' and 'pile/heap'. Context always makes it clear: 'een hoop problemen' = a pile of problems, 'ik heb hoop' = I have hope."},
        {type:"teach",trg:"het geloof",src:"the belief / faith",pos:"noun",gender:"n",note:"Het-word. 'Geloven' = to believe.\n'Geloof' can mean religious faith or general belief.\n'In het geloof' = in the faith.\n'Mijn geloof is dat...' = My belief is that...",example:"A: Het geloof speelt een grote rol in de maatschappij.\nB: Dat hangt af van het land.\nA: Ja, de reden verschilt per cultuur.",exampleSrc:"A: Belief plays a large role in society.\nB: That depends on the country.\nA: Yes, the reason differs per culture.",funFact:"From 'geloven' (to believe). Shares root with English 'believe' and German 'Glaube'. The ge- prefix here is not the past-participle marker but an old nominalization prefix."},
        {type:"teach",trg:"de overheid",src:"the government / public authority",pos:"noun",gender:"c",note:"De-word. Refers to public institutions broadly.\n'De overheid' = the government as system/authority.\n'De regering' = the executive government (cabinet).\n'Overheidsinstellingen' = public institutions.",example:"A: De overheid beschermt het milieu.\nB: Ja, de wet regelt dat.\nA: Dat is een belangrijk doel van de politiek.",exampleSrc:"A: The government protects the environment.\nB: Yes, the law regulates that.\nA: That is an important goal of politics.",funFact:"From 'overheer' (one who rules over). The -heid suffix turns adjectives and participles into abstract nouns. Same suffix: vrijheid (freedom), zekerheid (certainty), veiligheid (safety)."},
        {type:"teach",trg:"het gebied",src:"the area / field / region",pos:"noun",gender:"n",note:"Het-word. Plural: gebieden.\n'Op het gebied van...' = in the field of...\n'Een groot gebied' = a large area.\nUsed both geographically and figuratively.",example:"A: Op het gebied van de economie zijn er veel problemen.\nB: Ja, dat is een moeilijk gebied.\nA: De politiek zoekt oplossingen.",exampleSrc:"A: In the field of economics there are many problems.\nB: Yes, that is a difficult area.\nA: Politics is looking for solutions.",funFact:"Common in fixed expression 'op het gebied van' (in the area/field of). Also geographic: 'het Deltagebied' = the Delta region. Cognate with German 'Gebiet'."},
        {type:"teach",trg:"overtuigen",src:"to convince / to persuade",pos:"verb",gender:null,note:"Inseparable prefix: over-.\nPP: overtuigd (no ge-!).\n'Ik ben overtuigd' = I am convinced.\n'Iemand overtuigen van iets' = convince someone of something.",example:"A: Hoe kun je de politiek overtuigen?\nB: Je kunt de politiek overtuigen met feiten.\nA: Dat is de beste reden.",exampleSrc:"A: How can you convince politics?\nB: You can convince politics with facts.\nA: That is the best reason.",funFact:"Inseparable prefix over- (not separable like 'oversteken'). PP is 'overtuigd', not 'geovertuigd'. Same pattern: begrijpen → begrepen, ontdekken → ontdekt."},
        {type:"teach",trg:"beïnvloeden",src:"to influence",pos:"verb",gender:null,note:"Inseparable prefix: be-.\nPP: beïnvloed (no ge-!).\n'Beïnvloed door...' = influenced by...\n'De politiek beïnvloedt de economie.'\n= Politics influences the economy.",example:"A: De politiek beïnvloedt de economie.\nB: Ja, dat is heel belangrijk.\nA: De overheid beïnvloedt ook het milieu.",exampleSrc:"A: Politics influences the economy.\nB: Yes, that is very important.\nA: The government also influences the environment.",funFact:"The trema (¨) on the i is mandatory: be-in-vloe-den. Without it the word would read as 'beinvloeden'. Dutch uses the trema to signal a new syllable when two vowels don't form a diphthong."},
        {type:"teach",trg:"beschermen",src:"to protect",pos:"verb",gender:null,note:"Inseparable prefix: be-.\nPP: beschermd (no ge-!).\n'Het milieu beschermen' = to protect the environment.\n'Beschermd' = protected (adjective).",example:"A: We moeten het milieu beschermen.\nB: Dat is het doel van de overheid.\nA: Ja, duurzaam beleid is de oplossing.",exampleSrc:"A: We must protect the environment.\nB: That is the goal of the government.\nA: Yes, sustainable policy is the solution.",funFact:"PP is 'beschermd', not 'gebeschermend'. The be- prefix blocks ge-. Also a noun: 'de bescherming' (the protection), frequent in law and policy texts."},
        {type:"tip",title:"De vs. Het: Abstract Nouns",text:"Memorizing articles is easier with patterns:\n\nDE-WORDS (most abstract nouns ending in -heid, -ing, -nis):\nde betekenis, de hoop, de overheid\n\nHET-WORDS (often neuter, no reliable rule):\nhet doel, het geloof, het gebied\n\nTip: nouns ending in -heid are ALWAYS de-words.\n'Vrijheid, veiligheid, zekerheid' = all de-words.\n\nNouns ending in -nis vary:\n'de betekenis' but 'het gevangenis'.\nLearn article + noun as a unit."},
        {type:"mc",q:"'De overheid' refers to:",opts:["Public authority broadly","The parliament only","The city council only","The cabinet only"],ans:"Public authority broadly",hint:"Broader than 'de regering' (executive cabinet)"},
        {type:"fb",opts:["overtuigd","geovertuigd","overtuigen","overtuigde"],hint:"Inseparable prefix over- means the past participle has NO ge-",s:"Ik ben ___ door de feiten. (convinced)",a:"overtuigd"},
        {type:"match",pairs:[{trg:"de betekenis",src:"the meaning"},{trg:"het doel",src:"the goal"},{trg:"de hoop",src:"the hope"},{trg:"het geloof",src:"the belief"}]},
        {type:"fb",opts:["beschermd","gebeschermend","beschermt","beschermen"],hint:"PP of 'beschermen', inseparable prefix blocks ge-",s:"Het milieu wordt ___ door de wet. (protected)",a:"beschermd"},
        {type:"mc",q:"'Op het gebied van de economie' means:",opts:["Against the economy","In the field of economics","On the economy's surface","Near the economy"],ans:"In the field of economics",hint:"'Op het gebied van' = in the …/area of"},
        {type:"drag_fill",hint:"The goal is. The hope is.",s:"Het {1} van dit project is het milieu te {2}.",blanks:{"1":"doel","2":"beschermen"},pool:["doel","beschermen","geloof","overtuigen"]},
        {type:"mc",q:"Which nouns are ALWAYS de-words in Dutch?",opts:["Nouns ending in -el","All abstract nouns","Nouns ending in -heid","Nouns ending in -nis"],ans:"Nouns ending in -heid",hint:"Vrijheid, overheid, zekerheid... always de"},
        {type:"fb",opts:["beïnvloed","gebeïnvloed","beïnvloeden","beïnvloedde"],hint:"PP of 'beïnvloeden', inseparable be- blocks ge-",s:"De politiek heeft de economie sterk ___. (influenced)",a:"beïnvloed"},
        {type:"match",pairs:[{trg:"de overheid",src:"the government/authority"},{trg:"het gebied",src:"the area/field"},{trg:"overtuigen",src:"to convince"},{trg:"beschermen",src:"to protect"}]},
        {type:"drag_fill",hint:"Meaning. Convinced. Influence.",s:"De {1} van dit woord is duidelijk. De politiek {2} de economie. Kun jij mij {3}?",blanks:{"1":"betekenis","2":"beïnvloedt","3":"overtuigen"},pool:["betekenis","beïnvloedt","overtuigen","beschermt","doel"]},
        {type:"mc",q:"PP of 'overtuigen' is:",opts:["overtuigend","overtuigde","geovertuigd","overtuigd"],ans:"overtuigd",hint:"Inseparable prefix over- blocks ge-"},
        {type:"fb",opts:["hoop","geloof","doel","gebied"],hint:"De ___: hope, a de-word expressing expectation for the future",s:"Er is ___ dat de situatie verbetert.",a:"hoop"}
  ]}
]};
